781→        editCard.putExtra(NoteEditor.EXTRA_CALLER, NoteEditor.CALLER_REVIEWER_EDIT)
782→        editCard.putExtra(FINISH_ANIMATION_EXTRA, getInverseTransition(animation) as Parcelable)
783→        editorCard = currentCard
784→        startActivityForResultWithAnimation(editCard, EDIT_CURRENT_CARD, animation)
785→    }
